export const getPersonasByAccount = (accountId) =>
  PERSONAS.filter(p => p.accountId === accountId);

export const getPersonaById = (id) =>
  PERSONAS.find(p => p.id === id);

export const getPersonasByTier = (tier) =>
  PERSONAS.filter(p => p.seniorityTier === tier);

